// ---- src/state.js ----
const storageKey = "magic-smash-data-v1";
const initialData = {
	profile: "",
	language: "en",
	theme: "vehicles",
	colorMode: "light",
	duration: 5,
	sound: true,
	letterSize: 1,
	totalPresses: 0,
	totalSeconds: 0,
	keyCounts: {},
	uniqueKeys: [],
	bestSpeed: 0,
};

function loadData() {
	try {
		return JSON.parse(localStorage.getItem(storageKey)) || {};
	} catch {
		return {};
	}
}

let data = { ...initialData, ...loadData() };
const state = {
	playing: false,
	sessionPresses: 0,
	sessionKeys: new Set(),
	streak: 0,
	bestStreak: 0,
	lastKeyTime: 0,
	lastPointerTime: 0,
	startedAt: null,
	elapsedBeforePause: 0,
	timerId: null,
	backgroundShuffleId: null,
};

function saveData() {
	localStorage.setItem(storageKey, JSON.stringify(data));
}

function resetStats(keep) {
	data = { ...initialData, ...keep };
}

// ---- src/audio.js ----
let audioContext;

function playTone() {
	try {
		audioContext ||= new (window.AudioContext || window.webkitAudioContext)();
		const oscillator = audioContext.createOscillator();
		const gain = audioContext.createGain();
		const now = audioContext.currentTime;
		const musicNotes = [261.63, 293.66, 329.63, 392, 440, 523.25];
		oscillator.type = ["vehicles", "dinosaurs", "toys"].includes(data.theme)
			? "triangle"
			: data.theme === "lights"
				? "square"
				: "sine";
		oscillator.frequency.value =
			data.theme === "music"
				? musicNotes[Math.floor(Math.random() * musicNotes.length)]
				: data.theme === "bubbles"
					? 640 + Math.random() * 260
					: data.theme === "dinosaurs"
						? 130 + Math.random() * 80
						: data.theme === "farm"
							? 220 + Math.random() * 180
							: data.theme === "weather"
								? 270 + Math.random() * 130
								: data.theme === "bedtime"
									? 310 + Math.random() * 70
									: data.theme === "space"
										? 430 + Math.random() * 250
										: data.theme === "ocean"
											? 300 + Math.random() * 220
											: 370 + Math.random() * 270;
		if (data.theme === "vehicles")
			oscillator.frequency.exponentialRampToValueAtTime(230, now + 0.18);
		if (data.theme === "bubbles")
			oscillator.frequency.exponentialRampToValueAtTime(1020, now + 0.17);
		if (data.theme === "ocean")
			oscillator.frequency.exponentialRampToValueAtTime(190, now + 0.22);
		gain.gain.setValueAtTime(0.04, now);
		gain.gain.exponentialRampToValueAtTime(
			0.001,
			now + (data.theme === "music" ? 0.36 : 0.22),
		);
		oscillator.connect(gain).connect(audioContext.destination);
		oscillator.start();
		oscillator.stop(now + (data.theme === "music" ? 0.37 : 0.23));
	} catch {
		/* Sound is optional; silently continue when unavailable. */
	}
}

