// ---- src/effects.js ----
const BACKGROUND_SHUFFLE_INTERVAL_MS = 30000;
const THEME_EFFECT_BACKDROP_PROBABILITY = 0;
const BACKGROUND_ICON_GROWTH_ON_KEYPRESS = true;

function shouldUseThemeEffectBackdrop() {
	return (
		THEME_EFFECT_BACKDROP_PROBABILITY > 0 &&
		Math.random() < THEME_EFFECT_BACKDROP_PROBABILITY
	);
}

function createMagicBackground() {
	const layer = $("#magicLayer");
	const icons = themeIcons[data.theme];
	const colours = [
		"rgba(255,255,255,.86)",
		"var(--accent)",
		"var(--orb-c)",
		"rgba(255,255,255,.67)",
	];
	layer.replaceChildren();
	const largeObjects = [
		"vehicles",
		"bubbles",
		"music",
		"party",
		"space",
		"beach",
		"ocean",
		"toys",
	].includes(data.theme);
	for (let index = 0; index < (largeObjects ? 15 : 20); index++) {
		const object = document.createElement("span");
		object.className = "magic-object";
		object.textContent = icons[index % icons.length];
		object.style.setProperty("--left", `${4 + Math.random() * 92}%`);
		object.style.setProperty("--top", `${7 + Math.random() * 86}%`);
		object.style.setProperty(
			"--size",
			`${largeObjects ? 44 + Math.random() * 44 : 24 + Math.random() * 44}px`,
		);
		object.style.setProperty("--delay", `${-Math.random() * 8}s`);
		object.style.setProperty("--float-duration", `${4 + Math.random() * 5}s`);
		object.style.setProperty("--object-color", colours[index % colours.length]);
		layer.append(object);
	}
}

function startBackgroundShuffle() {
	clearInterval(state.backgroundShuffleId);
	state.backgroundShuffleId = window.setInterval(
		createMagicBackground,
		BACKGROUND_SHUFFLE_INTERVAL_MS,
	);
}

function animateBackground() {
	if (!BACKGROUND_ICON_GROWTH_ON_KEYPRESS) return;
	const objects = $$(".magic-object");
	for (const object of objects.sort(() => Math.random() - 0.5).slice(0, 5)) {
		object.classList.remove("pop-grow");
		void object.offsetWidth;
		object.classList.add("pop-grow");
		object.addEventListener(
			"animationend",
			() => object.classList.remove("pop-grow"),
			{ once: true },
		);
	}
}

function makeSparkles(event) {
	const rect = $("#keyOrb").getBoundingClientRect();
	const x = Number.isFinite(event.clientX)
		? event.clientX
		: rect.left + rect.width / 2;
	const y = Number.isFinite(event.clientY)
		? event.clientY
		: rect.top + rect.height / 2;
	const icons = themeIcons[data.theme];
	for (let i = 0; i < 5; i++) {
		const spark = document.createElement("span");
		spark.className = "spark";
		spark.textContent = icons[Math.floor(Math.random() * icons.length)];
		spark.style.setProperty("--x", `${x}px`);
		spark.style.setProperty("--y", `${y}px`);
		spark.style.setProperty("--dx", `${(Math.random() - 0.5) * 230}px`);
		spark.style.setProperty("--dy", `${(Math.random() - 0.5) * 230}px`);
		$("#sparkles").append(spark);
		spark.addEventListener("animationend", () => spark.remove());
	}
}

function makePointerTrail(event) {
	const trail = document.createElement("span");
	const rect = $("#keyOrb").getBoundingClientRect();
	const x = Number.isFinite(event.clientX)
		? event.clientX
		: rect.left + rect.width / 2;
	const y = Number.isFinite(event.clientY)
		? event.clientY
		: rect.top + rect.height / 2;
	trail.className = "pointer-trail";
	trail.textContent =
		themeIcons[data.theme][
			Math.floor(Math.random() * themeIcons[data.theme].length)
		];
	trail.style.setProperty("--x", `${x}px`);
	trail.style.setProperty("--y", `${y}px`);
	trail.style.setProperty("--dx", `${(Math.random() - 0.5) * 80}px`);
	trail.style.setProperty("--dy", `${-30 - Math.random() * 70}px`);
	$("#sparkles").append(trail);
	trail.addEventListener("animationend", () => trail.remove());
}

function makeThemeMechanic(event) {
	if (
		![
			"vehicles",
			"bubbles",
			"music",
			"colors",
			"weather",
			"dinosaurs",
			"farm",
			"party",
			"space",
			"beach",
			"ocean",
			"lights",
			"toys",
			"bedtime",
		].includes(data.theme)
	)
		return;
	const effects = $("#themeEffects");
	const rect = $("#keyOrb").getBoundingClientRect();
	const x = Number.isFinite(event.clientX)
		? event.clientX
		: rect.left + rect.width / 2;
	const y = Number.isFinite(event.clientY)
		? event.clientY
		: rect.top + rect.height / 2;

	if (data.theme === "vehicles") {
		const vehicle = document.createElement("span");
		vehicle.className = "theme-effect vehicle-effect";
		if (shouldUseThemeEffectBackdrop()) vehicle.classList.add("with-backdrop");
		vehicle.textContent =
			themeIcons.vehicles[
				Math.floor(Math.random() * themeIcons.vehicles.length)
			];
		vehicle.style.setProperty("--y", `${12 + Math.random() * 72}%`);
		effects.append(vehicle);
		vehicle.addEventListener("animationend", () => vehicle.remove());
		return;
	}

	if (
		[
			"colors",
			"weather",
			"dinosaurs",
			"farm",
			"party",
			"space",
			"beach",
			"ocean",
			"lights",
			"toys",
			"bedtime",
		].includes(data.theme)
	) {
		const effectCount = ["colors", "party"].includes(data.theme)
			? 6
			: data.theme === "lights"
				? 4
				: 3;
		const className = {
			colors: "color-effect",
			weather: "weather-effect",
			dinosaurs: "dinosaur-effect",
			farm: "farm-effect",
			party: "party-effect",
			space: "space-effect",
			beach: "beach-effect",
			ocean: "ocean-effect",
			lights: "lights-effect",
			toys: "toys-effect",
			bedtime: "bedtime-effect",
		}[data.theme];
		const symbols = {
			colors: ["🔴", "🟡", "🟢", "🔵", "🟣", "✨"],
			weather: themeIcons.weather,
			dinosaurs: ["👣", "🦕", "🌋"],
			farm: themeIcons.farm,
			party: themeIcons.party,
			space: themeIcons.space,
			beach: themeIcons.beach,
			ocean: themeIcons.ocean,
			lights: themeIcons.lights,
			toys: themeIcons.toys,
			bedtime: themeIcons.bedtime,
		}[data.theme];
		for (let index = 0; index < effectCount; index++) {
			const effect = document.createElement("span");
			effect.className = `theme-effect ${className}`;
			if (shouldUseThemeEffectBackdrop()) effect.classList.add("with-backdrop");
			effect.textContent = symbols[Math.floor(Math.random() * symbols.length)];
			effect.style.setProperty("--x", `${x + (Math.random() - 0.5) * 145}px`);
			effect.style.setProperty("--y", `${y + (Math.random() - 0.5) * 80}px`);
			effect.style.setProperty("--dx", `${(Math.random() - 0.5) * 180}px`);
			effect.style.setProperty("--dy", `${-40 - Math.random() * 150}px`);
			effects.append(effect);
			effect.addEventListener("animationend", () => effect.remove());
		}
		return;
	}

	const effectsPerTouch = data.theme === "bubbles" ? 4 : 3;
	for (let index = 0; index < effectsPerTouch; index++) {
		const effect = document.createElement("span");
		effect.className = `theme-effect ${data.theme === "bubbles" ? "bubble-effect" : "music-effect"}`;
		if (shouldUseThemeEffectBackdrop()) effect.classList.add("with-backdrop");
		effect.textContent =
			data.theme === "bubbles" ? "🫧" : ["♫", "♪", "♬"][index];
		effect.style.setProperty("--x", `${x + (Math.random() - 0.5) * 110}px`);
		effect.style.setProperty("--y", `${y + (Math.random() - 0.5) * 65}px`);
		effect.style.setProperty("--dx", `${(Math.random() - 0.5) * 155}px`);
		effect.style.setProperty("--dy", `${-45 - Math.random() * 125}px`);
		effects.append(effect);
		effect.addEventListener("animationend", () => effect.remove());
	}
}

function makeLetterTrail(letter) {
	const layer = $("#magicLayer");
	for (let index = 0; index < 9; index++) {
		const pop = document.createElement("span");
		pop.className = "letter-pop";
		pop.textContent = letter;
		pop.style.setProperty("--left", `${12 + Math.random() * 76}%`);
		pop.style.setProperty("--top", `${20 + Math.random() * 61}%`);
		pop.style.setProperty("--size", `${28 + Math.random() * 52}px`);
		pop.style.setProperty("--dx", `${(Math.random() - 0.5) * 330}px`);
		pop.style.setProperty("--dy", `${(Math.random() - 0.5) * 260}px`);
		pop.style.setProperty("--turn", `${-35 + Math.random() * 70}deg`);
		layer.append(pop);
		pop.addEventListener("animationend", () => pop.remove());
	}
}

// ---- src/i18n.js ----
// languageRegistry is injected by scripts/build.mjs from src/languages/*.json.
let languages = {};

function loadLanguages() {
	languages = languageRegistry;
}

function activeLanguage() {
	return (
		languages[data.language] || languages.en || Object.values(languages)[0]
	);
}
function t(key) {
	return activeLanguage()?.translations?.[key] ?? key;
}

function populateLanguageSelect() {
	$("#languageSelect").replaceChildren(
		...Object.values(languages).map((language) => {
			const option = document.createElement("option");
			option.value = language.code;
			option.textContent = language.name;
			return option;
		}),
	);
}

// ---- src/game.js ----
function formatTimer(seconds) {
	const safe = Math.max(0, Math.floor(seconds));
	return `${String(Math.floor(safe / 60)).padStart(2, "0")}:${String(safe % 60).padStart(2, "0")}`;
}

function displayKey(event) {
	if (event.key === " ") return "●";
	if (event.key.length === 1) return event.key.toUpperCase();
	const labels = {
		Enter: "↵",
		Backspace: "←",
		Tab: "↹",
		ArrowUp: "↑",
		ArrowDown: "↓",
		ArrowLeft: "←",
		ArrowRight: "→",
		Shift: "⇧",
		Control: "⌃",
		Alt: "⌥",
		Meta: "⌘",
		CapsLock: "⇪",
		Escape: "⎋",
		Delete: "⌦",
		Insert: "↳",
		Home: "↖",
		End: "↘",
		PageUp: "⇞",
		PageDown: "⇟",
		ContextMenu: "☰",
		ScrollLock: "⇳",
		NumLock: "⇭",
		Pause: "Ⅱ",
		PrintScreen: "▣",
	};
	return labels[event.key] || (event.key.startsWith("F") ? event.key : "✦");
}

function keyName(event) {
	if (event.key === " ") return t("space");
	return displayKey(event);
}

function updateStats() {
	const keyEntries = Object.entries(data.keyCounts || {});
	const favourite = keyEntries.sort((a, b) => b[1] - a[1])[0]?.[0] || "—";
	$("#totalPresses").textContent = data.totalPresses.toLocaleString();
	$("#totalMinutes").textContent = `${Math.floor(data.totalSeconds / 60)} min`;
	$("#totalUnique").textContent = data.uniqueKeys.length;
	$("#bestSpeed").textContent = data.bestSpeed;
	$("#favoriteKey").textContent = favourite;
	$("#sessionPresses").textContent = state.sessionPresses;
	$("#sessionStreak").textContent = state.bestStreak;
}

function updateStreak() {
	const word = state.streak === 1 ? t("sequence") : t("sequences");
	$("#streakText").textContent = `${state.streak} ${word}`;
}

function resetSession() {
	state.sessionPresses = 0;
	state.sessionKeys = new Set();
	state.streak = 0;
	state.bestStreak = 0;
	state.lastKeyTime = 0;
	state.startedAt = Date.now();
	state.elapsedBeforePause = 0;
	$("#keyOrb").textContent = "?";
	$("#keyName").textContent = t("letsPlay");
	$("#encouragement").textContent = "";
	updateStreak();
	updateStats();
}

function startGame() {
	if (state.playing) return;
	resetSession();
	state.playing = true;
	$("#welcomeCard").classList.add("hidden");
	$("#keyStage").classList.remove("hidden");
	$("#sessionChip").classList.remove("hidden");
	$("#bottomPrompt").classList.add("hidden");
	tick();
	state.timerId = window.setInterval(tick, 500);
}

function tick() {
	if (!state.playing) return;
	const elapsed = (Date.now() - state.startedAt) / 1000;
	if (Number(data.duration) === 0) {
		$("#timer").textContent = `+${formatTimer(elapsed)}`;
		return;
	}
	const remaining = Number(data.duration) * 60 - elapsed;
	$("#timer").textContent = formatTimer(remaining);
	if (remaining <= 0) endGame();
}

function endGame() {
	if (!state.playing) return;
	const elapsed = Math.max(
		1,
		Math.round((Date.now() - state.startedAt) / 1000),
	);
	state.playing = false;
	clearInterval(state.timerId);
	data.totalSeconds += elapsed;
	data.bestSpeed = Math.max(
		data.bestSpeed,
		Math.round((state.sessionPresses / elapsed) * 60),
	);
	saveData();
	updateStats();
	$("#keyStage").classList.add("hidden");
	$("#sessionChip").classList.add("hidden");
	$("#welcomeCard").classList.remove("hidden");
	$("#bottomPrompt").classList.remove("hidden");
	$("#endPresses").textContent = state.sessionPresses;
	$("#endUnique").textContent = state.sessionKeys.size;
	$("#endStreak").textContent = state.bestStreak;
	$("#endDialog").showModal();
}

function pressKey(event) {
	if (Object.keys(languages).length === 0) return;
	if (
		event.key === "Tab" ||
		event.key === " " ||
		event.key.startsWith("Arrow") ||
		["Alt", "Escape"].includes(event.key)
	)
		event.preventDefault();
	triggerInteraction(displayKey(event), keyName(event), event, { sound: true });
}

function triggerInteraction(
	displayed,
	label,
	point,
	{ sound = false, pointer = false, burst = false } = {},
) {
	if (!state.playing) startGame();
	const effectPoint = pointer ? point : randomEffectPoint();
	const now = Date.now();
	state.streak = now - state.lastKeyTime < 1600 ? state.streak + 1 : 1;
	state.bestStreak = Math.max(state.bestStreak, state.streak);
	state.lastKeyTime = now;
	state.sessionPresses++;
	state.sessionKeys.add(displayed);
	data.totalPresses++;
	data.keyCounts[displayed] = (data.keyCounts[displayed] || 0) + 1;
	if (!data.uniqueKeys.includes(displayed)) data.uniqueKeys.push(displayed);
	$("#keyOrb").textContent = displayed;
	$("#keyName").textContent = label;
	$("#encouragement").textContent =
		t("encouragement")[Math.floor(Math.random() * t("encouragement").length)];
	const orb = $("#keyOrb");
	orb.classList.remove("bounce");
	void orb.offsetWidth;
	orb.classList.add("bounce");
	if (pointer) makePointerTrail(point);
	if (!pointer || burst) {
		makeSparkles(effectPoint);
		makeLetterTrail(displayed);
	}
	makeThemeMechanic(effectPoint);
	animateBackground();
	updateStreak();
	updateStats();
	if (sound && data.sound) playTone();
	saveData();
}

function randomEffectPoint() {
	const horizontalPadding = Math.min(80, window.innerWidth * 0.12);
	const topPadding = Math.min(150, window.innerHeight * 0.2);
	return {
		clientX:
			horizontalPadding +
			Math.random() * Math.max(1, window.innerWidth - horizontalPadding * 2),
		clientY:
			topPadding +
			Math.random() * Math.max(1, window.innerHeight - topPadding - 65),
	};
}

function pressPointer(event) {
	if (
		Object.keys(languages).length === 0 ||
		event.target.closest("button, select, input, label")
	)
		return;
	if (!state.playing) return;
	const isMouseTrail =
		event.type === "pointermove" && event.pointerType === "mouse";
	if (event.type === "pointermove" && !isMouseTrail) return;
	const now = Date.now();
	if (isMouseTrail && now - state.lastPointerTime < 160) return;
	state.lastPointerTime = now;
	event.preventDefault();
	const icons = themeIcons[data.theme];
	const displayed = icons[Math.floor(Math.random() * icons.length)];
	triggerInteraction(displayed, displayed, event, {
		pointer: true,
		burst: event.type === "pointerdown",
		sound: event.type === "pointerdown",
	});
}

// ---- src/pwa.js ----
function notifyUpdate(worker, onUpdateReady) {
	if (typeof onUpdateReady !== "function") return;
	onUpdateReady(() => worker.postMessage("SKIP_WAITING"));
}

const IOS_TIP_DISMISSED_KEY = "magic-smash-ios-tip-dismissed";

function isIosDevice() {
	const ua = navigator.userAgent;
	if (/iPad|iPhone|iPod/.test(ua)) return true;
	// iPadOS 13+ identifies as "MacIntel" by default; touch support is the tell.
	return navigator.platform === "MacIntel" && navigator.maxTouchPoints > 1;
}

function isRunningStandalone() {
	return (
		window.navigator.standalone === true ||
		window.matchMedia("(display-mode: standalone)").matches
	);
}

function shouldShowIosInstallTip() {
	if (window.location.protocol === "file:") return false;
	if (!isIosDevice() || isRunningStandalone()) return false;
	try {
		return localStorage.getItem(IOS_TIP_DISMISSED_KEY) !== "true";
	} catch {
		// Some browsers (e.g. Safari private mode, storage fully disabled) can
		// throw on any localStorage access. This runs during startup, so a
		// thrown error here must not stop the rest of the app from booting.
		return false;
	}
}

function dismissIosInstallTip() {
	try {
		localStorage.setItem(IOS_TIP_DISMISSED_KEY, "true");
	} catch {
		/* Dismissing is best-effort; a full storage quota shouldn't block it. */
	}
}

// Chrome fetches a <link rel="manifest"> as soon as it's parsed, before any
// JS runs — and that fetch is blocked under file:// the same way ES module
// imports were. A static <link> in the HTML has no way to opt out, so the
// manifest is linked here instead, only when it can actually be fetched.
function linkManifest() {
	if (window.location.protocol === "file:") return;
	const link = document.createElement("link");
	link.rel = "manifest";
	link.href = "manifest.webmanifest";
	document.head.appendChild(link);
}

function registerServiceWorker(onUpdateReady) {
	if (!("serviceWorker" in navigator) || window.location.protocol === "file:")
		return;

	let reloading = false;
	navigator.serviceWorker.addEventListener("controllerchange", () => {
		if (reloading) return;
		reloading = true;
		window.location.reload();
	});

	window.addEventListener("load", () => {
		navigator.serviceWorker
			.register("./sw.js")
			.then((registration) => {
				if (registration.waiting)
					notifyUpdate(registration.waiting, onUpdateReady);
				registration.addEventListener("updatefound", () => {
					const newWorker = registration.installing;
					if (!newWorker) return;
					newWorker.addEventListener("statechange", () => {
						const isUpdate =
							newWorker.state === "installed" &&
							navigator.serviceWorker.controller;
						if (isUpdate) notifyUpdate(newWorker, onUpdateReady);
					});
				});
			})
			.catch(() => {
				/* Installing as an app is optional; ignore registration failures. */
			});
	});
}

// ---- src/ui.js ----
const KEY_BOUNCE_DURATION_MS = 340;

function applyAnimationSettings() {
	document.documentElement.style.setProperty(
		"--key-bounce-duration-ms",
		`${KEY_BOUNCE_DURATION_MS}ms`,
	);
}

function setLanguage(language) {
	if (!languages[language]) return;
	data.language = language;
	document.documentElement.lang = language === "pt-br" ? "pt-BR" : language;
	$("#languageSelect").value = language;
	$$("[data-i18n]").forEach((element) => {
		const key = element.dataset.i18n;
		if (key === "welcomeTitle") element.innerHTML = t(key);
		else element.textContent = t(key);
	});
	const profile = data.profile || t("unnamed");
	$("#profileName").textContent = profile;
	$("#childName").placeholder = t("unnamed");
	updateThemeName();
	updateColorMode();
	updateStreak();
	updateSound();
	updateStats();
	saveData();
}

function setTheme(theme) {
	if (!themeIcons[theme]) return;
	data.theme = theme;
	document.body.dataset.theme = theme;
	$$("[data-theme-choice]").forEach((button) => {
		button.classList.toggle("active", button.dataset.themeChoice === theme);
	});
	updateThemeName();
	createMagicBackground();
	saveData();
}

function updateThemeName() {
	const selectedThemeName = t(themeNames[data.theme]);
	$("#themeName").textContent = selectedThemeName;
	$("#quickThemeName").textContent = selectedThemeName;
}

function setColorMode(mode) {
	data.colorMode = mode === "dark" ? "dark" : "light";
	document.body.dataset.mode = data.colorMode;
	updateColorMode();
	saveData();
}

function updateColorMode() {
	$$("[data-mode-choice]").forEach((button) => {
		button.classList.toggle(
			"active",
			button.dataset.modeChoice === data.colorMode,
		);
	});
}

function updateLetterSize() {
	document.body.classList.toggle(
		"small-letters",
		Number(data.letterSize) === 0,
	);
	document.body.classList.toggle(
		"large-letters",
		Number(data.letterSize) === 2,
	);
	$("#letterSize").value = data.letterSize;
}

function updateDuration() {
	$$("[data-duration-select]").forEach((select) => {
		select.value = data.duration;
	});
}

function updateSound() {
	$$("[data-sound-toggle]").forEach((toggle) => {
		toggle.checked = data.sound;
	});
	$("#quickSoundState").textContent = t(data.sound ? "soundOn" : "soundOff");
}

function updateEndSessionButton() {
	$("#endSessionButton").classList.toggle("hidden", !state.playing);
}

function openPanel(type) {
	const isSettings = type === "settings";
	$("#settingsPanel").classList.toggle("hidden", !isSettings);
	$("#statsPanel").classList.toggle("hidden", isSettings);
	$("#panelTitle").textContent = t(isSettings ? "settings" : "stats");
	$("#panelEyebrow").textContent = isSettings ? t("caregivers") : t("allTime");
	updateStats();
	updateEndSessionButton();
	$("#sidePanel").classList.add("open");
	$("#sidePanel").setAttribute("aria-hidden", "false");
	$("#scrim").classList.add("show");
	$("#closePanel").focus();
}

function closePanel() {
	$("#sidePanel").classList.remove("open");
	$("#sidePanel").setAttribute("aria-hidden", "true");
	$("#scrim").classList.remove("show");
}

function showUpdateBanner(applyUpdate) {
	$("#updateBanner").classList.remove("hidden");
	$("#updateNowButton").addEventListener(
		"click",
		(event) => {
			event.currentTarget.disabled = true;
			applyUpdate();
		},
		{ once: true },
	);
}

function showIosInstallTip(onDismiss) {
	$("#iosInstallTip").classList.remove("hidden");
	$("#dismissIosTip").addEventListener(
		"click",
		() => {
			$("#iosInstallTip").classList.add("hidden");
			onDismiss();
		},
		{ once: true },
	);
}

async function shareSessionResults() {
	const text = t("shareText")
		.replace("{presses}", state.sessionPresses)
		.replace("{streak}", state.bestStreak);
	const shareData = { title: "Magic Smash", text, url: window.location.href };

	if (navigator.share) {
		try {
			await navigator.share(shareData);
		} catch {
			/* The user closing the share sheet isn't a failure to react to. */
		}
		return;
	}

	if (!navigator.clipboard) return;
	try {
		await navigator.clipboard.writeText(`${text} ${shareData.url}`);
		const label = $("#shareButton").querySelector("[data-i18n]");
		const original = label.textContent;
		label.textContent = t("linkCopied");
		setTimeout(() => {
			label.textContent = original;
		}, 2000);
	} catch {
		/* Clipboard access can be denied by the browser; nothing more to try. */
	}
}

